COLOR_PTR = $fd

.segment "STARTUP"

basic_start:
    .word basic_next
    .word 10
    .byte $9e
    .byte "2061", 0
basic_next:
    .word 0

start:
    sei
    lda #$00
    sta $d020
    sta $d021
    jsr install_custom_charset
    lda #$1c
    sta $d018
    jsr clear_screen
    jsr render_board
    lda #$00
    sta path_index
    jsr draw_pacman

walk_loop:
    jsr delay_frame
    jsr erase_pacman_cell
    inc path_index
    lda path_index
    cmp #PATH_LEN
    bcc continue_walk
    lda #$02
    sta $d020
stop_game:
    jmp stop_game

continue_walk:
    jsr draw_pacman
    jmp walk_loop

delay_frame:
    ldx #$90
delay_outer:
    ldy #$ff
delay_inner:
    dey
    bne delay_inner
    dex
    bne delay_outer
    rts

set_screen_ptr_for_index:
    ldx path_index
    lda path_screen_lo,x
    sta SCREEN_PTR
    lda path_screen_hi,x
    sta SCREEN_PTR+1
    rts

set_color_ptr_for_index:
    ldx path_index
    lda path_color_lo,x
    sta COLOR_PTR
    lda path_color_hi,x
    sta COLOR_PTR+1
    rts

erase_pacman_cell:
    jsr set_screen_ptr_for_index
    ldy #$00
    lda #$00
    sta (SCREEN_PTR),y
    jsr set_color_ptr_for_index
    lda #$00
    sta (COLOR_PTR),y
    rts

draw_pacman:
    jsr set_screen_ptr_for_index
    ldy #$00
    ldx path_index
    lda path_char,x
    sta (SCREEN_PTR),y
    jsr set_color_ptr_for_index
    lda #$07
    sta (COLOR_PTR),y
    rts

install_custom_charset:
    ldx #$00
copy_charset_loop:
    lda custom_charset,x
    sta CUSTOM_CHARSET_ADDR,x
    inx
    cpx #CUSTOM_CHARSET_BYTES
    bne copy_charset_loop
    rts

clear_screen:
    ldx #$00
clear_loop:
    lda #$00
    sta $0400,x
    sta $0500,x
    sta $0600,x
    sta $06e8,x
    lda #$00
    sta $d800,x
    sta $d900,x
    sta $da00,x
    sta $dae8,x
    inx
    bne clear_loop
    rts

